	chain cni-npr-68fa4a3547cba8fa5fd75d4 {
		iifname != "cni-podman0" tcp dport 80 dnat to 10.88.0.11:8080
	}

	chain cni-npo-68fa4a3547cba8fa5fd75d4 {
		iifname "cni-podman0" ip saddr 10.88.0.11 ip daddr 224.0.0.0/24 counter packets 0 bytes 0 return
		iifname "cni-podman0" ip saddr 10.88.0.11 ip daddr 255.255.255.255 counter packets 0 bytes 0 return
		iifname "cni-podman0" ip saddr 10.88.0.11 counter packets 0 bytes 0 masquerade
	}
}
table ip raw {
	chain prerouting {
		type filter hook prerouting priority raw; policy accept;
	}
}
table ip filter {
	chain forward {
		type filter hook forward priority filter; policy drop;
		jump cni-ffw-68fa4a3547cba8fa5fd75d4
		oifname "cni-podman0" ip daddr 10.88.0.11 tcp dport 8080 counter packets 3 bytes 192 accept
		log prefix "ip4 forward drop: "
		counter packets 0 bytes 0 drop
	}

	chain cni-ffw-68fa4a3547cba8fa5fd75d4 {
		oifname "cni-podman0" ip daddr 10.88.0.11 ct state established,related counter packets 30 bytes 3457 accept
		iifname "cni-podman0" ip saddr 10.88.0.11 counter packets 33 bytes 24736 accept
		iifname "cni-podman0" oifname "cni-podman0" counter packets 0 bytes 0 accept
	}
}
```
